const escapeHtml = (value: string) => {
  return value
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
};

const splitExampleLine = (line: string) => {
  const separator = line.indexOf(':');

  if (separator === -1) {
    return { label: '', value: line };
  }

  return {
    label: line.slice(0, separator),
    value: line.slice(separator + 1).trim(),
  };
};

