const renderExampleCard = (step: LandingStep) => {
  if (step.exampleVariant === 'strategy-cards') {
    return renderStrategyCards(step);
  }

  if (step.exampleVariant === 'tick-timeline') {
    return renderTickTimeline(step);
  }

  if (step.exampleVariant === 'result-cards') {
    return renderResultCards(step);
  }

  return `
    <div class="example-card">
      <div class="example-topline">
        <span>${escapeHtml(step.exampleEyebrow)}</span>
        <span>${escapeHtml(step.exampleTitle)}</span>
      </div>
      <div class="example-body">
        ${step.exampleLines
          .map((line) => {
            const parts = splitExampleLine(line);

            return `<div class="example-line">${parts.label ? `<span class="example-label">${escapeHtml(parts.label)}</span><strong class="example-value">${escapeHtml(parts.value)}</strong>` : `<strong class="example-value example-value-full">${escapeHtml(parts.value)}</strong>`}</div>`;
          })
          .join('')}
      </div>
    </div>
  `;
};

